const items = $input.all();
const errorData = items[0]?.json || {};

const output = {
  success: false,
  error: {
    message: errorData.execution?.error?.message || "Unknown error occurred",
    node: errorData.execution?.error?.node?.name || "Unknown node",
    workflow_name: errorData.workflow?.name || "Unknown workflow",
    workflow_id: errorData.workflow?.id || "Unknown ID",
    timestamp: new Date().toISOString()
  }
};

return [{ json: output }];
